  1	import * as React from 'react';
  2	import * as _ from 'lodash';
  3	import classNames from 'classnames';
  4	import { useTranslation } from 'react-i18next';
  5	import { DomainPropType, DomainTuple } from 'victory-core';
  6	import {
  7	  Chart,
  8	  ChartAxis,
  9	  ChartAxisProps,
 10	  ChartBar,
 11	  ChartGroup,
 12	  ChartThemeColor,
 13	  ChartVoronoiContainer,
 14	} from '@patternfly/react-charts/victory';
 15	import { Alert, Card, CardBody, CardTitle } from '@patternfly/react-core';
 16	import { useFlag } from '@openshift-console/dynamic-plugin-sdk';
 17	import {
 18	  formatDate,
 19	  getDropDownDate,
 20	  getXaxisValues,
 21	  hourformat,
 22	  parsePrometheusDuration,
 23	  monthYear,
 24	} from './dateTime';
 25	import { getResultsSummary } from '../utils/summary-api';
 26	import { DataType, FLAGS, SummaryResponse } from '../../types';
 27	import { ALL_NAMESPACES_KEY } from '../../consts';
 28	import { getFilter, useInterval } from './utils';
 29	import { LoadingInline } from '../Loading';
 30	
 31	interface PipelinesRunsNumbersChartProps {
 32	  namespace?: string;
 33	  timespan?: number;
 34	  interval?: number;
 35	  domain?: DomainPropType;
 36	  parentName?: string;
 37	  bordered?: boolean;
 38	  kind?: string;
 39	  width?: number;
 40	}
 41	type DomainType = { x?: DomainTuple; y?: DomainTuple };
 42	
 43	const getChartData = (
 44	  tickValues: number[] | Date[],
 45	  data: SummaryResponse,
 46	  type: string,
 47	) => {
 48	  const chartData = tickValues?.map((value) => {
 49	    const s = data?.summary?.find((d) => {
 50	      const group_date = new Date(Number(d.group_value) * 1000);
 51	      if (type == 'hour') {
 52	        return group_date.getHours() === value;
 53	      }
 54	      if (type == 'day' || type == 'week') {
 55	        return group_date.toDateString() === new Date(value).toDateString();
 56	      }
 57	      if (type == 'month') {
 58	        return group_date.getMonth() === value.getMonth();
 59	      }
 60	    });
 61	    return {
 62	      x: value,
 63	      y: s?.total || 0,
 64	    };
 65	  });
 66	  return chartData;
 67	};
 68	
 69	const PipelinesRunsNumbersChart: React.FC<PipelinesRunsNumbersChartProps> = ({
 70	  namespace,
 71	  timespan,
 72	  interval,
 73	  domain,
 74	  parentName,
 75	  bordered,
 76	  kind,
 77	  width = 530,
 78	}) => {
 79	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 80	  const isDevConsoleProxyAvailable = useFlag(FLAGS.DEVCONSOLE_PROXY);
 81	  const startTimespan = timespan - parsePrometheusDuration('1d');
 82	  const endDate = new Date(Date.now()).setHours(0, 0, 0, 0);
 83	  const startDate = new Date(Date.now() - startTimespan).setHours(0, 0, 0, 0);
 84	  const { x: domainX, y: domainY } = (domain as DomainType) || {};
 85	  const domainValue: DomainPropType = {
 86	    x: domainX || [startDate, endDate],
 87	    y: domainY || undefined,
 88	  };
 89	
 90	  const [data, setData] = React.useState<SummaryResponse>();
 91	  const [loaded, setLoaded] = React.useState(false);
 92	  const [pipelineRunsChartError, setPipelineRunsChartError] = React.useState<
 93	    string | undefined
 94	  >();
 95	  const abortControllerRef = React.useRef<AbortController>();
 96	
 97	  if (namespace == ALL_NAMESPACES_KEY) {
 98	    namespace = '-';
 99	  }
100	
101	  React.useEffect(() => {
102	    return () => {
103	      abortControllerRef.current?.abort();
104	    };
105	  }, []);
106	
107	  const [tickValues, type] = getXaxisValues(timespan);
108	  const date = getDropDownDate(timespan).toISOString();
109	
110	  const getSummaryData = (group_by: string) => {
111	    abortControllerRef.current?.abort();
112	    abortControllerRef.current = new AbortController();
113	    setData(undefined);
114	
115	    const summaryOpt = {
116	      summary: 'total',
117	      data_type: DataType?.PipelineRun,
118	      filter: getFilter(date, parentName, kind),
119	      groupBy: group_by,
120	    };
121	    setPipelineRunsChartError(undefined);
122	    setLoaded(false);
123	    getResultsSummary(
124	      namespace,
125	      summaryOpt,
126	      undefined,
127	      isDevConsoleProxyAvailable,
128	      abortControllerRef.current.signal,
129	      90000,
130	    )
131	      .then((d) => {
132	        setLoaded(true);
133	        setPipelineRunsChartError(undefined);
134	        setData(d);
135	      })
136	      .catch((e) => {
137	        if (e.name === 'AbortError') {
138	          // Request was cancelled, this is expected behavior
139	          return;
140	        }
141	        setLoaded(true);
142	        setPipelineRunsChartError(
143	          e.message || t('Failed to load pipeline runs number data'),
144	        );
145	        setData(undefined);
146	      });
147	  };
148	
149	  React.useEffect(() => {
150	    setLoaded(false);
151	    setPipelineRunsChartError(undefined);
152	    setData(undefined);
153	  }, [namespace, timespan]);
154	
155	  let xTickFormat;
156	  let dayLabel;
157	  let showLabel = false;
158	  let chartData = [];
159	  switch (type) {
160	    case 'hour':
161	      xTickFormat = (d) => hourformat(d);
162	      showLabel = true;
163	      domainValue.x = [0, 23];
164	      useInterval(() => getSummaryData('hour'), interval, namespace, date);
165	      dayLabel = formatDate(new Date());
166	      chartData = getChartData(tickValues, data, 'hour');
167	      break;
168	    case 'day':
169	      xTickFormat = (d) => formatDate(d);
170	      domainValue.x = [startDate, endDate];
171	      useInterval(() => getSummaryData('day'), interval, namespace, date);
172	      chartData = getChartData(tickValues, data, 'day');
173	      break;
174	    case 'week':
175	      xTickFormat = (d) => formatDate(d);
176	      domainValue.x = [new Date(tickValues[0]), new Date(tickValues[11])];
177	      useInterval(() => getSummaryData('week'), interval, namespace, date);
178	      chartData = getChartData(tickValues, data, 'week');
179	      break;
180	    case 'month':
181	      xTickFormat = (d) => monthYear(d);
182	      domainValue.x = [new Date(tickValues[0]), new Date(tickValues[11])];
183	      useInterval(() => getSummaryData('month'), interval, namespace, date);
184	      chartData = getChartData(tickValues, data, 'month');
185	      break;
186	    default:
187	      console.log('Received wrong data');
188	      break;
189	  }
190	
191	  const max: number = Math.max(...chartData.map((yVal) => yVal.y));
192	  !isNaN(max) && max > 5
193	    ? (domainValue.y = [0, max])
194	    : (domainValue.y = [0, 5]);
195	
196	  if (!domainY) {
197	    let minY: number = _.minBy(chartData, 'y')?.y ?? 0;
198	    let maxY: number = _.maxBy(chartData, 'y')?.y ?? 0;
199	    if (minY === 0 && maxY === 0) {
200	      minY = -1;
201	      maxY = 1;
202	    } else if (minY > 0 && maxY > 0) {
203	      minY = 0;
204	    } else if (minY < 0 && maxY < 0) {
205	      maxY = 0;
206	    }
207	    domainValue.y = [minY, maxY];
208	  }
209	
210	  let xAxisStyle: ChartAxisProps['style'] = {
211	    tickLabels: { fill: 'var(--pf-t--global--text--color--regular)', fontSize: 12 },
212	  };
213	  const yAxisStyle: ChartAxisProps['style'] = {
214	    tickLabels: { fill: 'var(--pf-t--global--text--color--regular)', fontSize: 12 },
215	  };
216	  if (tickValues.length > 7) {
217	    xAxisStyle = {
218	      tickLabels: {
219	        fill: 'var(--pf-t--global--text--color--regular)',
220	        angle: 320,
221	        fontSize: 10,
222	        textAnchor: 'end',
223	        verticalAnchor: 'end',
224	      },
225	    };
226	  }
227	
228	  return (
229	    <>
230	      <Card
231	        className={classNames({
232	          'pipeline-overview__number-of-plr-card':!pipelineRunsChartError,
233	          'card-border': bordered,
234	        })}
235	      >
236	        <CardTitle className="pipeline-overview__number-of-plr-card__title">
237	          <span>{t('Number of PipelineRuns')}</span>
238	        </CardTitle>
239	        <CardBody 
240	          className={classNames({
241	            'pipeline-overview__number-of-plr-card__body':!pipelineRunsChartError,
242	          })}
243	          >
244	          {pipelineRunsChartError ? (
245	            <Alert
246	              variant="danger"
247	              isInline
248	              title={t('Unable to load pipeline runs')}
249	              className="pf-v6-u-mb-md pf-v6-u-mt-lg"
250	            />
251	          ) : (
252	            <div className="pipeline-overview__number-of-plr-card__bar-chart-div">
253	              {loaded ? (
254	                <Chart
255	                  containerComponent={
256	                    <ChartVoronoiContainer
257	                      labels={({ datum }) => `${datum.y}`}
258	                      constrainToVisibleArea
259	                    />
260	                  }
261	                  scale={{ x: 'time', y: 'linear' }}
262	                  domain={domainValue}
263	                  domainPadding={{ x: [30, 25] }}
264	                  height={145}
265	                  width={width}
266	                  padding={{
267	                    top: 10,
268	                    bottom: 55,
269	                    left: 50,
270	                  }}
271	                  themeColor={ChartThemeColor.blue}
272	                >
273	                  <ChartAxis
274	                    tickValues={tickValues}
275	                    style={xAxisStyle}
276	                    tickFormat={xTickFormat}
277	                    label={showLabel ? dayLabel : ''}
278	                  />
279	                  <ChartAxis dependentAxis style={yAxisStyle} />
280	                  <ChartGroup>
281	                    <ChartBar data={chartData} barWidth={18} />
282	                  </ChartGroup>
283	                </Chart>
284	              ) : (
285	                <div className="pipeline-overview__number-of-plr-card__loading pf-v6-u-h-100">
286	                  <LoadingInline />
287	                </div>
288	              )}
289	            </div>
290	          )}
291	        </CardBody>
292	      </Card>
293	    </>
294	  );
295	};
296	
297	export default PipelinesRunsNumbersChart;

